`define CYCLE_TIME  20.0

module PATTERN(
    // output signals
    clk,
    rst_n,
    i_valid,
    i_iter,
    i_mode,
    i_data,
    i_weight,
	
    // input signals
    o_valid,
    o_data
);

// ========================================
// I/O declaration
// ========================================
// Output
output reg          clk;
output reg          rst_n;
output reg          i_valid;
output reg    [2:0] i_iter;
output reg    [1:0] i_mode;
output reg    [7:0] i_data;
output reg    [3:0] i_weight;

// Input
input               o_valid;
input         [7:0] o_data;

// ========================================
// clock
// ========================================
real CYCLE = `CYCLE_TIME;
initial clk = 1'b0;
always	#(CYCLE/2.0) clk = ~clk; //clock

// ========================================
// integer & parameter
// ========================================
parameter WEIGHT_NUM = 1312;
parameter LIMIT = 150;

integer input_file, output_file;
integer total_latency, calc_latency;
integer PATNUM;
integer pat, idx;
integer weight;
integer k, q, i, j, ch;
integer out_num;
integer golden_out;
integer iter;
integer mode;
integer total_iter;
// ========================================
// wire & reg
// ========================================



//================================================================
// design
//================================================================
initial begin
    input_file = $fopen("../00_TESTBED/input.txt", "r");
    output_file = $fopen("../00_TESTBED/output.txt", "r");

    rst_n = 1'd1;
    i_valid = 1'd0;
    i_data = 8'dx;
    i_iter = 3'dx;
    i_mode = 2'dx;
    i_weight = 4'dx;

	total_latency = 0;
	calc_latency = 0;
    total_iter = 0;
    reset_signal_task;

    k = $fscanf(input_file, "%d", PATNUM);

    $display("     WEIGHT INPUT START  ");
    input_weight_task;
    $display("     WEIGHT INPUT OVER  ");
    repeat(2)@(negedge clk);

    for(pat = 0; pat < PATNUM; pat = pat + 1)begin
        $display("     START PATTERN %0d   ", pat);
        input_data_task;
        $display("     IMG INPUT OVER   ");
        wait_o_valid;
        check_ans;
        $display("\033[32m   PASS PATTERN %0d WITH %0d CYCLES\033[0m", pat, calc_latency);
        @(negedge clk);
        total_iter = total_iter + iter;
        // $display("   PASS PATTERN %0d WITH %0d CYCLES ", pat, calc_latency);
    end
    // display_good;
    $display("======================================================");
    $display("                 ALL PATTERN PASS !!!                    ");
    $display("          Average latency: %0d cycles", total_latency/total_iter);
    $display("          Total latency:   %0d cycles", total_latency);
    $display("======================================================");
    $finish;
end

task reset_signal_task;
begin
    $display("     RESET START      ");
    force clk = 0;
	#(CYCLE);
	rst_n = 0;
	repeat(3)#(CYCLE);
	if((o_valid !== 0) || (o_data !== 0))begin
        // display_weird;
        $display("\033[31m ERROR: OUTPUT SIGNEL SHOULD BE 0 AFTER RESET! \033[0m");
		// $display("   OUTPUT SIGNEL SHOULD BE 0 AFTER RESET     ");
		$finish;
	end
	rst_n = 1;
	#(CYCLE);
	release clk;
    // @(negedge clk);
    $display("     RESET OVER      ");
end
endtask

task input_data_task;
begin
    @(negedge clk);
    q = $fscanf(input_file, "%d", iter); 
    q = $fscanf(input_file, "%d", mode); 
    for(i=0; i<64; i=i+1)begin
        for(j=0; j<64; j=j+1)begin
            i_valid = 1'd1;
            if(i == 0 && j == 0)begin 
                i_iter = iter;
                i_mode = mode;
            end
            else begin 
                i_iter = 3'dx;
                i_mode = 2'dx;
            end
            q = $fscanf(input_file, "%d", i_data); 
            @(negedge clk);
        end
    end
    // @(negedge clk);
    i_data = 8'dx;
    i_valid = 1'd0;
end
endtask

task input_weight_task;
begin
    @(negedge clk);
    for(i=0; i<WEIGHT_NUM; i=i+1)begin
        i_valid = 1'd1;
        q = $fscanf(input_file, "%d", i_weight); 
        @(negedge clk);
    end
    i_weight = 4'dx;
    i_valid = 1'd0;
end
endtask

task wait_o_valid;
    calc_latency = 0;
    while(o_valid !== 1'd1)begin
        calc_latency = calc_latency + 1;
        @(negedge clk);
        if(calc_latency > LIMIT*1000*iter)begin
            // display_weird;
			$display("\033[31m            EXECUTION CYCLE OVER %0dk         \033[0m", LIMIT*iter);
			$finish;
		end
    end
endtask

task check_ans;
    out_num = 0;
    while(out_num !== 4096)begin
        if(o_valid === 1'd1)begin
            q = $fscanf(output_file, "%d", golden_out);
            if(o_data !== golden_out)begin
                // display_bad;
                $display("\033[31m            FAIL at CYCLE %0d !!!          \033[0m", calc_latency);
                $display("\033[31m            PAT NUM %0d %0dst OUTPUT     \033[0m", pat, out_num);
                $display("\033[31m            GOLDEN = %0d, YOURS = %0d     \033[0m", golden_out, o_data);
                $finish;
            end
            @(negedge clk);
            out_num = out_num + 1;
        end
        else begin
            @(negedge clk);
            calc_latency = calc_latency + 1;
            if(calc_latency > LIMIT*1000*iter)begin
                // display_weird;
                if(out_num !== 4096)begin
                    // display_bad;
                    $display("\033[31m ERROR: TOTAL SHOULD BE 64x64 OUTPUT \033[0m");
                end
                $display("\033[31m            EXECUTION CYCLE OVER %0dk         \033[0m", LIMIT*iter);
                $finish;
            end
        end
    end
    // if(out_num !== 4096)begin
    //     display_bad;
    //     $display("\033[31m ERROR: TOTAL SHOULD BE 64x64 OUTPUT \033[0m");
    // end
    total_latency = total_latency + calc_latency;
endtask

